const raw = (input || '').trim();
const sp = raw.indexOf(' ');
const mode = (sp === -1 ? raw : raw.slice(0, sp)).toLowerCase();
const rest = sp === -1 ? '' : raw.slice(sp + 1);
function enc(s) { return (typeof btoa === 'function') ? btoa(unescape(encodeURIComponent(s))) : Buffer.from(s, 'utf8').toString('base64'); }
function dec(s) { return (typeof atob === 'function') ? decodeURIComponent(escape(atob(s))) : Buffer.from(s, 'base64').toString('utf8'); }
if (mode === 'enc') { return enc(rest); }
if (mode === 'dec') { try { return dec(rest); } catch (e) { return 'invalid base64'; } }
return 'usage: !b64 enc <text>  |  !b64 dec <text>';

