const [board, move, nick] = input.split('|');
const cells = (board || '_________').split('');
const i = parseInt(move, 10) - 1;
let mark = (cells.filter(c => c === 'X').length <= cells.filter(c => c === 'O').length) ? 'X' : 'O';
let status = '';
if (cells[i] && cells[i] !== '_') {
  status = 'Cell taken, pick another.';
} else {
  cells[i] = mark;
  const b = cells;
  const wins = [[0,1,2],[3,4,5],[6,7,8],[0,3,6],[1,4,7],[2,5,8],[0,4,8],[2,4,6]];
  const won = wins.some(w => b[w[0]] !== '_' && b[w[0]] === b[w[1]] && b[w[1]] === b[w[2]]);
  if (won) status = mark + ' wins!';
  else if (b.every(c => c !== '_')) status = "It's a draw!";
  else status = mark + ' played by ' + nick + '.';
}
return cells.join('') + '||' + status;

