var raw = (INPUT || ARGS || '').trim();
var table = [[1000,'M'],[900,'CM'],[500,'D'],[400,'CD'],[100,'C'],[90,'XC'],[50,'L'],[40,'XL'],[10,'X'],[9,'IX'],[5,'V'],[4,'IV'],[1,'I']];
var out;
if (/^[0-9]+$/.test(raw)) {
  var n = parseInt(raw, 10);
  if (n < 1 || n > 3999) {
    out = 'Number must be between 1 and 3999.';
  } else {
    var r = '';
    for (var i = 0; i < table.length; i++) {
      while (n >= table[i][0]) { r += table[i][1]; n -= table[i][0]; }
    }
    out = raw + ' = ' + r;
  }
} else if (/^[MDCLXVI]+$/i.test(raw)) {
  var s = raw.toUpperCase();
  var total = 0, idx = 0;
  for (var j = 0; j < table.length; j++) {
    while (s.substr(idx, table[j][1].length) === table[j][1]) { total += table[j][0]; idx += table[j][1].length; }
  }
  out = idx === s.length ? (s + ' = ' + total) : ('Invalid Roman numeral: ' + raw);
} else {
  out = 'Usage: !roman 2024  or  !roman MMXXIV';
}
print(out);

