const parts = (INPUT || '').trim().split(/\s+/);
const a = (parts[0] || '').trim();
const b = (parts[1] || '').trim();
// order-independent deterministic hash so ship(a,b) == ship(b,a)
const pair = [a.toLowerCase(), b.toLowerCase()].sort().join('\u0000');
let h = 2166136261;
for (let i = 0; i < pair.length; i++) {
  h ^= pair.charCodeAt(i);
  h = (h * 16777619) >>> 0;
}
const score = h % 101; // 0..100, always the same for the same pair
// merged ship-name: first half of a + second half of b
const left = a.slice(0, Math.max(1, Math.ceil(a.length / 2)));
const right = b.slice(Math.floor(b.length / 2));
const shipName = (left + right) || (a + b);
let verdict;
if (score >= 90) verdict = 'soulmates! \uD83D\uDC95';
else if (score >= 70) verdict = 'a strong match \uD83D\uDC96';
else if (score >= 50) verdict = 'pretty cute together \uD83D\uDE0A';
else if (score >= 30) verdict = 'it could work \uD83E\uDD1E';
else verdict = 'just friends \uD83E\uDD1D';
print('\uD83D\uDC98 ' + a + ' + ' + b + ' = ' + shipName + ' \u2014 ' + score + '% ' + verdict);

