const parts = String(input || '').trim().split(/\s+/);
if (parts.length < 3) { return 'Usage: !unit <number> <from> <to> (e.g. !unit 10 km mi)'; }
const n = parseFloat(parts[0]);
if (isNaN(n)) { return 'First argument must be a number, e.g. !unit 10 km mi'; }
const from = parts[1].toLowerCase();
const to = parts[2].toLowerCase();

// length in metres, weight in grams
const length = { mm: 0.001, cm: 0.01, m: 1, km: 1000, in: 0.0254, ft: 0.3048, yd: 0.9144, mi: 1609.344 };
const weight = { mg: 0.001, g: 1, kg: 1000, t: 1000000, oz: 28.349523125, lb: 453.59237, st: 6350.29318 };
const tempAliases = { c: 'c', celsius: 'c', f: 'f', fahrenheit: 'f', k: 'k', kelvin: 'k' };

function round(x) { return Math.round(x * 10000) / 10000; }

let result;
if (from in length && to in length) {
  result = round(n * length[from] / length[to]);
} else if (from in weight && to in weight) {
  result = round(n * weight[from] / weight[to]);
} else if (from in tempAliases && to in tempAliases) {
  const f = tempAliases[from], t = tempAliases[to];
  let celsius;
  if (f === 'c') celsius = n;
  else if (f === 'f') celsius = (n - 32) * 5 / 9;
  else celsius = n - 273.15;
  if (t === 'c') result = round(celsius);
  else if (t === 'f') result = round(celsius * 9 / 5 + 32);
  else result = round(celsius + 273.15);
} else {
  return 'Cannot convert ' + from + ' to ' + to + '. Try length (km, mi, m, ft), weight (kg, lb, g, oz) or temperature (c, f, k).';
}
return n + ' ' + from + ' = ' + result + ' ' + to;

